from cryptography.fernet import Fernet

# Load encryption key from config
key = config['ENCRYPTION_KEY']
cipher_suite = Fernet(key.encode('utf-8'))

def encrypt_credit_card(credit_card_number):
    """Encrypts a credit card number."""
    encrypted_number = cipher_suite.encrypt(credit_card_number.encode('utf-8'))
    return encrypted_number.decode('utf-8')

def decrypt_credit_card(encrypted_number):
    """Decrypts an encrypted credit card number."""
    decrypted_number = cipher_suite.decrypt(encrypted_number.encode('utf-8'))
    return decrypted_number.decode('utf-8')